// src/Login.js
import React, { useState } from "react";
import { createClient } from "@supabase/supabase-js";
import { motion } from "framer-motion";
import { Loader2, Eye, EyeOff, LogIn, Code2 } from "lucide-react";

const supabase = createClient(
    process.env.REACT_APP_SUPABASE_URL,
    process.env.REACT_APP_SUPABASE_KEY
);

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [show, setShow] = useState(false);
    const [err, setErr] = useState("");
    const [loading, setLoading] = useState(false);

    const handleLogin = async (e) => {
        e.preventDefault();
        setErr("");
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();
            if (error || !data) {
                setErr("❌ Hatalı kullanıcı adı veya şifre!");
                return;
            }
            localStorage.setItem("kullanici", JSON.stringify(data));
            onLoginSuccess?.();
        } catch (e2) {
            console.error(e2);
            setErr("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-root">
            <style>{css}</style>

            {/* Logo */}
            <motion.div
                className="logo"
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6 }}
            >
                <motion.div
                    className="logo-icon"
                    animate={{ rotate: [0, 10, -10, 0] }}
                    transition={{ repeat: Infinity, duration: 6, ease: "easeInOut" }}
                >
                    <Code2 size={42} />
                </motion.div>
                <div className="logo-text">
                    <span className="dev">Software Developer</span>
                    <span className="name">Görkem Çadırcı</span>
                </div>
            </motion.div>

            {/* Login Card */}
            <motion.form
                onSubmit={handleLogin}
                className="card"
                initial={{ opacity: 0, scale: 0.96 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
            >
                <div className="card-head">
                    <LogIn size={18} />
                    <span>Giriş Yap</span>
                </div>

                <div className="field">
                    <label>Kullanıcı Adı</label>
                    <input
                        type="text"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                        autoComplete="username"
                        placeholder="gorkem"
                    />
                </div>

                <div className="field">
                    <label>Şifre</label>
                    <div className="pass">
                        <input
                            type={show ? "text" : "password"}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            autoComplete="current-password"
                            placeholder="••••••••"
                        />
                        <button
                            type="button"
                            className="eye"
                            onClick={() => setShow((s) => !s)}
                        >
                            {show ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>
                </div>

                {err && <div className="alert">{err}</div>}

                <button type="submit" className="btn" disabled={loading}>
                    {loading ? (
                        <span className="btn-inner">
                            <Loader2 className="spin" size={16} /> Giriş yapılıyor…
                        </span>
                    ) : (
                        "Giriş"
                    )}
                </button>
            </motion.form>
        </div>
    );
}

/* ==== CSS ==== */
const css = `
:root{
  --bg:#050a13;
  --card:#0f1b31f2;
  --border:rgba(255,255,255,.1);
  --text:#eaf1ff;
  --muted:#9db0c9;
  --primary:#38bdf8;
  --primary2:#0ea5e9;
  --shadow:0 20px 60px rgba(0,0,0,.55);
}

*{box-sizing:border-box}
body,html,#root,.login-root{height:100%;margin:0;font-family:Inter,ui-sans-serif}
.login-root{
  background:radial-gradient(circle at top left,rgba(14,165,233,.3),transparent 50%),var(--bg);
  display:flex; flex-direction:column; align-items:center; justify-content:center;
  gap:30px; overflow:hidden;
}

/* Logo */
.logo{display:flex; flex-direction:column; align-items:center; gap:8px;}
.logo-icon{
  color:var(--primary); display:flex; align-items:center; justify-content:center;
  width:72px; height:72px; border-radius:50%;
  border:2px solid var(--primary2);
  box-shadow:0 0 30px rgba(56,189,248,.35);
}
.logo-text{display:flex; flex-direction:column; align-items:center}
.logo-text .dev{font-size:13px; color:var(--muted);}
.logo-text .name{font-size:20px; font-weight:700; background:linear-gradient(90deg,var(--primary),var(--primary2));-webkit-background-clip:text;color:transparent;}

/* Card */
.card{
  width:min(400px,90%); padding:22px; border-radius:18px;
  background:var(--card); border:1px solid var(--border);
  box-shadow:var(--shadow); display:grid; gap:14px;
  color:var(--text); position:relative;
}
.card-head{display:flex; align-items:center; gap:8px; font-weight:600; margin-bottom:6px;}

.field{display:grid; gap:6px}
.field label{font-size:13px; color:var(--muted);}
.field input{
  border:1px solid var(--border); border-radius:12px;
  padding:12px; background:rgba(255,255,255,.06); color:var(--text);
  outline:none; transition:border .2s, box-shadow .2s;
}
.field input:focus{border-color:var(--primary); box-shadow:0 0 0 3px rgba(56,189,248,.25)}

.pass{position:relative}
.eye{
  position:absolute; right:10px; top:50%; transform:translateY(-50%);
  border:0; background:none; color:var(--muted); cursor:pointer;
}
.eye:hover{color:var(--text)}

.alert{
  background:rgba(239,68,68,.12); border:1px solid rgba(239,68,68,.35);
  color:#ffd6d6; border-radius:10px; padding:8px 10px; font-size:13px;
}

.btn{
  border:0; border-radius:12px; background:linear-gradient(100deg,var(--primary2),var(--primary));
  color:white; font-weight:600; padding:12px; cursor:pointer; transition:.2s;
}
.btn:hover{filter:brightness(1.05)}
.btn:disabled{opacity:.65; cursor:not-allowed}
.btn-inner{display:inline-flex; gap:8px; align-items:center}
.spin{animation:spin 1s linear infinite}
@keyframes spin{to{transform:rotate(360deg)}}
`;
